SELECT id, plan_code AS planCode, production_line_code AS productionLineCode, production_line_name AS productionLineName, maintenance_category AS maintenanceCategory, maintenance_start_time AS maintenanceStartTime, maintenance_end_time AS maintenanceEndTime, status, creator_id AS creatorId, creator_username AS creatorUsername, creator_name AS creatorName, created_at AS createdAt, updated_at AS updatedAt FROM maintenance_plan
AND creator_id = #{creatorId}
AND plan_code LIKE CONCAT('%', #{planCode}, '%')
AND production_line_code LIKE CONCAT('%', #{productionLineCode}, '%')
AND maintenance_category = #{maintenanceCategory}
AND status = #{status}
AND status != #{excludeStatus}
ORDER BY id DESC

